#!/usr/bin/env node
// Populate the `<!-- agent-surfaces-* -->` marker blocks in hand-maintained
// docs from the single source of truth: KNOWN_SURFACES / IMPLEMENTED_SURFACES
// in src/init/hook-packs/register.ts (CAWS-DOCS-AGENT-SURFACES-SINGLE-SOURCE-001).
//
// The command-reference.md doc is FULLY generated by generate-command-reference.mjs
// (it reads allowedValues off the --agent-surface option). The hand-maintained
// prose docs (README.md, docs/guides/agent-integration-guide.md) cannot be fully
// generated — their surrounding prose is human-authored — so this script fills
// ONLY the delimited marker regions, leaving everything else byte-identical.
//
// Marker contract: each registered target carries one or more marker pairs
//   <!-- <name>:start -->
//   ... generated content ...
//   <!-- <name>:end -->
// The populator replaces the content between each pair. Idempotent: re-runs
// produce byte-identical output. Fails loudly if a registered marker pair is
// missing from a target (so the docs cannot silently drift).
//
// Usage:
//   node scripts/populate-doc-markers.mjs            # write all registered docs
//   node scripts/populate-doc-markers.mjs --check    # exit 1 if any doc is stale
//   node scripts/populate-doc-markers.mjs --stdout   # print the snippet file only

import fs from 'node:fs';
import path from 'node:path';
import { createRequire } from 'node:module';
import { fileURLToPath } from 'node:url';
import { execFileSync } from 'node:child_process';

// Pure renderers + marker replacement live in the CommonJS helper so the jest
// test (CommonJS) and this ESM wrapper share one implementation.
const require = createRequire(import.meta.url);
const {
  renderSurfaceList,
  renderReadmeInstallBlock,
  renderGuideSurfaceProse,
  surfaceConsistency,
  fillMarkers,
} = require('./lib/agent-surfaces.cjs');

// Re-export for the test (which loads this module's pure surface via the .cjs).
export {
  renderSurfaceList,
  renderReadmeInstallBlock,
  renderGuideSurfaceProse,
  surfaceConsistency,
  fillMarkers,
};

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const PKG_ROOT = path.resolve(__dirname, '..');
const REPO_ROOT = path.resolve(PKG_ROOT, '..', '..');
const REGISTER_PATH = path.join(PKG_ROOT, 'dist', 'init', 'hook-packs', 'register.js');

// ─── Surface constants (the single source of truth) ─────────────────────────

/**
 * Resolve the canonical package's register.js when the local dist is absent
 * (linked git worktrees cannot build dist). Mirrors the generator's
 * canonicalMetadataPath fallback. The register exports are pure data, identical
 * across trees for the same committed source.
 */
function canonicalRegisterPath() {
  try {
    const commonDir = execFileSync('git', ['rev-parse', '--git-common-dir'], {
      cwd: PKG_ROOT,
      encoding: 'utf8',
    }).trim();
    const canonicalRoot = path.dirname(path.resolve(PKG_ROOT, commonDir));
    return path.join(canonicalRoot, 'packages', 'caws-cli', 'dist', 'init', 'hook-packs', 'register.js');
  } catch {
    return null;
  }
}

export function loadSurfaces(registerPath = REGISTER_PATH) {
  let resolved = registerPath;
  if (!fs.existsSync(resolved)) {
    const canonical = canonicalRegisterPath();
    if (canonical && fs.existsSync(canonical)) {
      resolved = canonical;
    } else {
      throw new Error(
        `register.js not found at ${registerPath} (nor at the canonical dist) — run the package build first.`
      );
    }
  }
  const mod = require(resolved);
  if (!Array.isArray(mod.KNOWN_SURFACES) || !Array.isArray(mod.IMPLEMENTED_SURFACES)) {
    throw new Error('register.js did not export KNOWN_SURFACES / IMPLEMENTED_SURFACES arrays.');
  }
  return {
    known: /** @type {readonly string[]} */ (mod.KNOWN_SURFACES),
    implemented: /** @type {readonly string[]} */ (mod.IMPLEMENTED_SURFACES),
  };
}

// ─── Registry: which docs get which markers ──────────────────────────────────

/** @param {{ known: readonly string[], implemented: readonly string[] }} surfaces */
function docTargets(surfaces) {
  return [
    {
      path: path.join(PKG_ROOT, 'README.md'),
      fills: [{ name: 'agent-surfaces-install', content: renderReadmeInstallBlock(surfaces.implemented) }],
    },
    {
      path: path.join(REPO_ROOT, 'docs', 'guides', 'agent-integration-guide.md'),
      fills: [
        {
          name: 'agent-surfaces-prose',
          content: renderGuideSurfaceProse(surfaces.known, surfaces.implemented),
          inline: true,
        },
      ],
    },
  ];
}

// ─── CLI ─────────────────────────────────────────────────────────────────────

function main(argv) {
  const check = argv.includes('--check');
  const toStdout = argv.includes('--stdout');

  const surfaces = loadSurfaces();
  const offenders = surfaceConsistency(surfaces.known, surfaces.implemented);
  if (offenders.length > 0) {
    process.stderr.write(
      `IMPLEMENTED_SURFACES lists surfaces not in KNOWN_SURFACES: ${offenders.join(', ')}\n`
    );
    return 1;
  }

  if (toStdout) {
    // Print the snippet reference (all three blocks) for ad-hoc inspection.
    process.stdout.write(renderSnippetFile(surfaces));
    return 0;
  }

  const targets = docTargets(surfaces);
  let stale = false;
  for (const target of targets) {
    const rel = path.relative(REPO_ROOT, target.path);
    if (!fs.existsSync(target.path)) {
      process.stderr.write(`target doc not found: ${rel}\n`);
      return 1;
    }
    const current = fs.readFileSync(target.path, 'utf8');
    let next;
    try {
      next = fillMarkers(current, target.fills);
    } catch (err) {
      process.stderr.write(`${rel}: ${err.message}\n`);
      return 1;
    }
    if (next === current) {
      process.stderr.write(`${rel}: up to date.\n`);
      continue;
    }
    if (check) {
      stale = true;
      process.stderr.write(`${rel}: STALE. Re-run: node packages/caws-cli/scripts/populate-doc-markers.mjs\n`);
      continue;
    }
    fs.writeFileSync(target.path, next);
    process.stderr.write(`${rel}: populated.\n`);
  }
  return stale ? 1 : 0;
}

/** Render the standalone snippet reference file (all three blocks). Exported
 *  for the sync test and for --stdout. */
export function renderSnippetFile({ known, implemented }) {
  const blocks = [
    ['agent-surfaces-list', renderSurfaceList(known)],
    ['agent-surfaces-implemented', renderImplemented(implemented)],
    ['agent-surfaces-declared-only', renderDeclaredOnly(known, implemented)],
  ];
  return (
    blocks
      .map(
        ([name, body]) =>
          `<!-- ${name}:start -->\n${body}\n<!-- ${name}:end -->`
      )
      .join('\n') + '\n'
  );
}

if (import.meta.url === `file://${process.argv[1]}`) {
  try {
    process.exit(main(process.argv.slice(2)));
  } catch (err) {
    process.stderr.write(`populate-doc-markers: ${err.stack || err.message}\n`);
    process.exit(2);
  }
}
